//! `lumen-bench` — the performance + correctness harness from PERF-GOAL.md.
//!
//! Produces the (search-type × data-volume) matrix: for each cell it builds a
//! deterministic corpus, runs the query many times to get true latency
//! percentiles (engine mode — pure index cost, no HTTP), verifies the answer
//! against a brute-force oracle, and grades engine-`p99` against the per-class
//! budget. Output is a human table + machine JSON; `--baseline` compares two
//! runs against the regression threshold.
//!
//! The corpus is generated by *pure functions of the doc index* (`doc_*`
//! below), so the oracle re-derives any document from its index alone — no
//! second copy of the corpus is held in memory.
//!
//! ```text
//! lumen-bench run --tiers xs,s,m --out report.json
//! lumen-bench run --tiers m --types term,match_single,knn --queries 5000
//! lumen-bench compare --baseline before.json --against report.json
//! ```

use std::collections::HashSet;
use std::time::Instant;

use anyhow::{bail, Context, Result};
use clap::{Parser, Subcommand};
use serde::{Deserialize, Serialize};

use lumen::storage::{Engine, MAX_INDEX_ITEMS};
use lumen::types::{
    Analyzer, CreateCollectionRequest, DuplicatesRequest, FieldSpec, FieldType, FieldValue,
    KnnQuery, MatchOp, MatchQuery, QueryNode, RangeQuery, SearchRequest, TermQuery, TermsQuery,
    VectorBackend, VectorMetric,
};

// ---------------------------------------------------------------------------
// Deterministic generation — every doc is a pure function of its index.
// ---------------------------------------------------------------------------

/// splitmix64 — a fast, well-distributed integer hash. Lets both indexing
/// and the oracle derive the same field values from a doc index.
fn mix(mut x: u64) -> u64 {
    x = x.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = x;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
    z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
    z ^ (z >> 31)
}

