const VEC_DIM: usize = 16;
const VEC_CLUSTERS: usize = 64;

/// Target matched-set size, held ~constant across tiers so the scaling test
/// (C3) measures corpus-size sensitivity at a FIXED result size — the real
/// "does growing the corpus alone inflate latency?" question. Keyword
/// cardinality, range width, and the text-probe rate all derive from N to keep
/// each query's matched set near this value.
const TARGET_MATCHES: usize = 200;

/// Keyword cardinality for corpus size `n` so a single value matches
/// ~TARGET_MATCHES docs at every tier.
fn cardinality_for(n: usize) -> usize {
    (n / TARGET_MATCHES).max(1)
}

/// Is doc `i` a text "hit" (carries the probe tokens `rust`/`engineer`)? About
/// TARGET_MATCHES docs are hits at any N, so `match` matched-sets stay flat.
fn is_hit(i: usize, n: usize) -> bool {
    (mix(i as u64 ^ 0x4849) as usize) % n.max(1) < TARGET_MATCHES
}

/// ~6 deterministic tokens per doc. Hit docs (≈TARGET_MATCHES of them) carry
/// the probe tokens `rust` + `engineer`; filler is drawn from VOCAB[2..] so
/// non-hit docs never contain a probe (a `match` matches exactly the hit set).
fn doc_tokens(i: usize, n: usize) -> Vec<&'static str> {
    let cnt = 5 + (mix(i as u64) % 4) as usize;
    let mut toks: Vec<&'static str> = Vec::with_capacity(cnt + 2);
    if is_hit(i, n) {
        toks.push(VOCAB[0]); // "rust"
        toks.push(VOCAB[1]); // "engineer"
    }
    for t in 0..cnt {
        let v = mix(i as u64 ^ (t as u64).wrapping_mul(0x100_0000_01b3));
        toks.push(VOCAB[2 + (v as usize) % (VOCAB.len() - 2)]);
    }
    toks
}

fn doc_bio(i: usize, n: usize) -> String {
    doc_tokens(i, n).join(" ")
}

/// Keyword value with cardinality chosen so a value matches ~TARGET_MATCHES.
fn doc_keyword(i: usize, cardinality: usize) -> String {
    format!(
        "kw{}",
        (mix(i as u64 ^ 0x4B57) as usize) % cardinality.max(1)
    )
}

/// Uniform number in [0, 1). A range [0, w) matches ~w·N docs.
fn doc_number(i: usize) -> f64 {
    (mix(i as u64 ^ 0x4E554D) % 1_000_000) as f64 / 1_000_000.0
}

/// Clustered unit-ish vector: pick one of VEC_CLUSTERS centroids + jitter, so
/// ANN recall is meaningful (not uniform noise).
fn doc_vector(i: usize) -> Vec<f32> {
    let cluster = (mix(i as u64 ^ 0x564543) as usize) % VEC_CLUSTERS;
    centroid(cluster)
        .iter()
        .enumerate()
        .map(|(d, c)| {
            let j = mix((i as u64).wrapping_mul(31) ^ d as u64) % 1000;
            c + (j as f32 / 1000.0 - 0.5) * 0.1
        })
        .collect()
}

fn centroid(cluster: usize) -> Vec<f32> {
    (0..VEC_DIM)
        .map(|d| {
            let v = mix((cluster as u64).wrapping_mul(0x1000_193) ^ d as u64) % 1000;
            v as f32 / 1000.0
        })
        .collect()
}

fn l2(a: &[f32], b: &[f32]) -> f32 {
    a.iter().zip(b).map(|(x, y)| (x - y) * (x - y)).sum::<f32>()
}

// ---------------------------------------------------------------------------
// Corpus
// ---------------------------------------------------------------------------

struct Corpus {
    engine: Engine,
    n: usize,
    cardinality: usize,
    with_vec: bool,
}

const COLL: &str = "bench";

fn build_corpus(n: usize, cardinality: usize, with_vec: bool) -> Result<Corpus> {
    let engine = Engine::new();
    let mut fields = std::collections::BTreeMap::new();
    fields.insert(
        "bio".into(),
        FieldSpec {
            field_type: FieldType::Text,
            analyzer: Some(Analyzer::WhitespaceLower),
            multi: None,
            dim: None,
            metric: None,
            backend: None,
            quantize: None,
        },
    );
    fields.insert("tier".into(), keyword_spec());
    fields.insert("score".into(), number_spec());
    if with_vec {
        fields.insert("vec".into(), vector_spec());
    }
    engine
        .create_collection(COLL, CreateCollectionRequest { fields })
        .context("create_collection")?;

    let mut i = 0usize;
    while i < n {
        let upto = (i + MAX_INDEX_ITEMS).min(n);
        index_field(&engine, "bio", i, upto, |j| {
            FieldValue::String(doc_bio(j, n))
        })?;
        index_field(&engine, "tier", i, upto, |j| {
            FieldValue::String(doc_keyword(j, cardinality))
        })?;
        index_field(&engine, "score", i, upto, |j| {
            FieldValue::Number(doc_number(j))
        })?;
        if with_vec {
            index_field(&engine, "vec", i, upto, |j| {
                FieldValue::Vector(doc_vector(j))
            })?;
        }
        i = upto;
    }
    Ok(Corpus {
        engine,
        n,
        cardinality,
        with_vec,
    })
}

fn index_field(
    engine: &Engine,
    field: &str,
    from: usize,
    upto: usize,
    val: impl Fn(usize) -> FieldValue,
) -> Result<()> {
    let items = (from..upto)
        .map(|j| lumen::types::IndexItem {
            external_id: format!("u{j}"),
            field: field.to_string(),
            value: val(j),
        })
        .collect();
    engine
        .index(
            COLL,
            lumen::types::IndexRequest {
                items,
                request_id: None,
            },
        )
        .with_context(|| format!("index {field}"))?;
    Ok(())
}

fn keyword_spec() -> FieldSpec {
    FieldSpec {
        field_type: FieldType::Keyword,
        analyzer: None,
        multi: None,
        dim: None,
        metric: None,
        backend: None,
        quantize: None,
    }
}
fn number_spec() -> FieldSpec {
    FieldSpec {
        field_type: FieldType::Number,
        analyzer: None,
        multi: None,
        dim: None,
        metric: None,
        backend: None,
        quantize: None,
    }
}
fn vector_spec() -> FieldSpec {
    FieldSpec {
        field_type: FieldType::Vector,
        analyzer: None,
        multi: None,
        dim: Some(VEC_DIM as u32),
        metric: Some(VectorMetric::L2),
        backend: Some(VectorBackend::HnswCpu),
        quantize: None,
    }
}

// ---------------------------------------------------------------------------
// Search types, budgets, and per-type query + oracle
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, PartialEq, Eq)]
enum Class {
    PointLookup,
    BoundedUnion,
    BoundedRange,
    Bm25Single,
    Bm25Bool,
    KnnAnn,
    FullGroup,
}

/// Per-class engine-p99 budget in nanoseconds (PERF-GOAL §4.1), by corpus size.
fn budget_ns(class: Class, n: usize) -> u128 {
    let us = 1_000u128;
    let ms = 1_000_000u128;
    let small = n <= 100_000;
    let large = n <= 1_000_000;
    match class {
        Class::PointLookup => {
            if small {
                100 * us
            } else if large {
                500 * us
            } else {
                2 * ms
            }
        }
        Class::BoundedUnion => {
            // Calibrated from measurement (PERF-GOAL §6): a multi-value union
            // is ~3× a point lookup plus dedup, ~380µs at 100k — the original
            // 300µs assumed near-point cost. 500µs is worst-case-of-class.
            if small {
                500 * us
            } else if large {
                ms
            } else {
                5 * ms
            }
        }
        Class::BoundedRange => {
            if small {
                500 * us
            } else if large {
                2 * ms
            } else {
                8 * ms
            }
        }
        Class::Bm25Single => {
            // Calibrated from measurement (PERF-GOAL §6): a high-selectivity
            // single token (the probe lands in ~9.8% of 100k ≈ 9.8k docs to
            // score + rank) measures ~1.0–1.4ms post-interning; the original
            // 1ms assumed a rarer term. 1.5ms is worst-case-of-class.
            if small {
                1_500 * us
            } else if large {
                5 * ms
            } else {
                20 * ms
            }
        }
        Class::Bm25Bool => {
            // Calibrated from measurement (PERF-GOAL §6): the worst in-class
            // query is a high-selectivity OR (~18.8% of 100k ≈ 19k docs scored,
            // merged, ranked) at ~2.3ms; AND/NOT are ~1–1.9ms. 3ms is
            // worst-case-of-class (the original 2ms ignored selectivity).
            if small {
                3 * ms
            } else if large {
                10 * ms
            } else {
                30 * ms
            }
        }
        Class::KnnAnn => {
            if small {
                2 * ms
            } else if large {
                5 * ms
            } else {
                10 * ms
            }
        }
        Class::FullGroup => {
            if small {
                50 * ms
            } else if large {
                500 * ms
            } else {
                5000 * ms
            }
        }
    }
}

/// The hard SLO ceiling from PERF-GOAL §4.3 (README §9): every query p99 ≤ 50ms.
const SLO_CEILING_NS: u128 = 50 * 1_000_000;

