fn wide_terms(q: usize, cardinality: usize) -> Vec<FieldValue> {
    let c = cardinality.max(1);
    let width = (c / 50).clamp(1, 1024);
    (0..width)
        .map(|k| FieldValue::String(format!("kw{}", (q + k) % c)))
        .collect()
}

fn wide_terms_set(q: usize, cardinality: usize) -> HashSet<String> {
    wide_terms(q, cardinality)
        .into_iter()
        .filter_map(|v| match v {
            FieldValue::String(s) => Some(s),
            _ => None,
        })
        .collect()
}

/// Build the q-th query of a given type. Varying `q` avoids measuring a single
/// hot value, while keeping the selectivity class fixed.
fn make_query(ty: &str, q: usize, corpus: &Corpus) -> SearchRequest {
    let c = corpus.cardinality;
    let kw = |v: usize| FieldValue::String(format!("kw{}", v % c.max(1)));
    // Range width chosen so [0, w) matches ~TARGET_MATCHES at this tier.
    let range_hi = (TARGET_MATCHES as f64 / corpus.n as f64).min(1.0);
    // The probe tokens carried only by hit docs (~TARGET_MATCHES of them).
    let query = match ty {
        "term" => QueryNode::Term(TermQuery {
            field: "tier".into(),
            value: kw(q),
        }),
        "terms" => QueryNode::Terms(TermsQuery {
            field: "tier".into(),
            values: vec![kw(q), kw(q + 1), kw(q + 2)],
        }),
        "range" => QueryNode::Range(RangeQuery {
            field: "score".into(),
            gt: None,
            gte: Some(0.0),
            lt: Some(range_hi),
            lte: None,
        }),
        "bool_filter" => QueryNode::And(vec![
            QueryNode::Terms(TermsQuery {
                field: "tier".into(),
                values: wide_terms(q, c),
            }),
            QueryNode::Range(RangeQuery {
                field: "score".into(),
                gt: None,
                gte: Some(0.30),
                lt: Some(0.46),
                lte: None,
            }),
        ]),
        "match_single" => QueryNode::Match(MatchQuery {
            field: "bio".into(),
            text: "rust".into(),
            op: MatchOp::And,
        }),
        "match_and" => QueryNode::Match(MatchQuery {
            field: "bio".into(),
            text: "rust engineer".into(),
            op: MatchOp::And,
        }),
        "match_or" => QueryNode::Match(MatchQuery {
            field: "bio".into(),
            text: "rust engineer".into(),
            op: MatchOp::Or,
        }),
        "filtered_search" => QueryNode::And(vec![
            QueryNode::Match(MatchQuery {
                field: "bio".into(),
                text: "backend".into(),
                op: MatchOp::And,
            }),
            QueryNode::Terms(TermsQuery {
                field: "tier".into(),
                values: wide_terms(q, c),
            }),
            QueryNode::Range(RangeQuery {
                field: "score".into(),
                gt: None,
                gte: Some(0.30),
                lt: Some(0.46),
                lte: None,
            }),
        ]),
        "not" => QueryNode::And(vec![
            QueryNode::Match(MatchQuery {
                field: "bio".into(),
                text: "rust".into(),
                op: MatchOp::And,
            }),
            QueryNode::Not(Box::new(QueryNode::Term(TermQuery {
                field: "tier".into(),
                value: kw(q),
            }))),
        ]),
        "knn" => QueryNode::Knn(KnnQuery {
            field: "vec".into(),
            vector: centroid(q % VEC_CLUSTERS),
            k: 10,
        }),
        other => panic!("unknown search type {other}"),
    };
    SearchRequest {
        query,
        limit: if ty == "knn" { 10 } else { 20 },
        cursor: None,
        sort: None,
        track_total: true,
        collapse: None,
    }
}

/// Brute-force oracle: re-derive every doc from its index and check the engine
/// agrees. Returns (score, measured_selectivity), where score is 1.0/0.0 for
/// exact query types and the recall@k fraction for `knn` (averaged by the
/// caller — approximate ANN is graded on mean recall, not per-query).
fn verify(ty: &str, q: usize, corpus: &Corpus) -> Result<(f64, f64)> {
    let n = corpus.n;
    let c = corpus.cardinality;
    let req = make_query(ty, q, corpus);
    let resp = corpus.engine.search(COLL, req).context("oracle search")?;

    let ok = match ty {
        "term" => {
            let want = format!("kw{}", q % c.max(1));
            let truth = (0..n).filter(|&i| doc_keyword(i, c) == want).count();
            resp.total as usize == truth
                && resp
                    .hits
                    .iter()
                    .all(|h| doc_keyword(eid(&h.external_id), c) == want)
        }
        "terms" => {
            let want: HashSet<String> = (0..3)
                .map(|k| format!("kw{}", (q + k) % c.max(1)))
                .collect();
            let truth = (0..n)
                .filter(|&i| want.contains(&doc_keyword(i, c)))
                .count();
            resp.total as usize == truth
        }
        "range" => {
            let hi = (TARGET_MATCHES as f64 / n as f64).min(1.0);
            let truth = (0..n).filter(|&i| doc_number(i) < hi).count();
            resp.total as usize == truth
        }
        "bool_filter" => {
            let want = wide_terms_set(q, c);
            let truth = (0..n)
                .filter(|&i| {
                    want.contains(&doc_keyword(i, c))
                        && doc_number(i) >= 0.30
                        && doc_number(i) < 0.46
                })
                .count();
            resp.total as usize == truth
                && resp.hits.iter().all(|h| {
                    let i = eid(&h.external_id);
                    want.contains(&doc_keyword(i, c))
                        && doc_number(i) >= 0.30
                        && doc_number(i) < 0.46
                })
        }
        "knn" => {
            // Distance-based recall@k vs exact brute-force kNN. Returned early
            // as a fraction (the caller averages over the sample).
            let probe = centroid(q % VEC_CLUSTERS);
            let mut dists: Vec<f32> = (0..n).map(|i| l2(&probe, &doc_vector(i))).collect();
            dists.sort_by(|a, b| a.partial_cmp(b).unwrap());
            let kth = dists.get(9).copied().unwrap_or(f32::INFINITY);
            // 5% relative slack: dense clusters pack thousands of near-tied
            // points, so the exact 10th vs 11th distance differ by ≪1%. A
            // returned neighbor within 5% of the exact kth distance is an
            // equivalent answer; a wrong-cluster hit is far outside it.
            let bound = kth * 1.05 + 1e-6;
            let within = resp
                .hits
                .iter()
                .filter(|h| l2(&probe, &doc_vector(eid(&h.external_id))) <= bound)
                .count();
            let recall = within as f64 / 10.0;
            return Ok((recall, resp.total as f64 / n as f64));
        }
        "match_single" | "match_and" | "match_or" | "not" => {
            // Membership + descending-score sanity (a full BM25 reference
            // scorer is a follow-up; PERF-GOAL §5). Every returned hit must
            // carry the probe token "rust" (only hit docs do).
            let descending = resp
                .hits
                .windows(2)
                .all(|w| w[0].score >= w[1].score - 1e-6);
            let members = resp
                .hits
                .iter()
                .all(|h| doc_tokens(eid(&h.external_id), n).contains(&"rust"));
            descending && members
        }
        "filtered_search" => {
            let want = wide_terms_set(q, c);
            let truth = (0..n)
                .filter(|&i| {
                    doc_tokens(i, n).contains(&"backend")
                        && want.contains(&doc_keyword(i, c))
                        && doc_number(i) >= 0.30
                        && doc_number(i) < 0.46
                })
                .count();
            let descending = resp
                .hits
                .windows(2)
                .all(|w| w[0].score >= w[1].score - 1e-6);
            resp.total as usize == truth
                && descending
                && resp.hits.iter().all(|h| {
                    let i = eid(&h.external_id);
                    doc_tokens(i, n).contains(&"backend")
                        && want.contains(&doc_keyword(i, c))
                        && doc_number(i) >= 0.30
                        && doc_number(i) < 0.46
                })
        }
        "duplicates" => true, // graded separately below
        _ => false,
    };

    let selectivity = resp.total as f64 / n as f64;
    Ok((if ok { 1.0 } else { 0.0 }, selectivity))
}

fn eid(external_id: &str) -> usize {
    external_id.trim_start_matches('u').parse().unwrap_or(0)
}

// ---------------------------------------------------------------------------
// Latency
// ---------------------------------------------------------------------------

fn pct(sorted: &[u128], p: f64) -> u128 {
    if sorted.is_empty() {
        return 0;
    }
    let idx = ((sorted.len() as f64 - 1.0) * p).round() as usize;
    sorted[idx.min(sorted.len() - 1)]
}

#[derive(Serialize, Deserialize, Clone)]
struct Cell {
    search: String,
    tier: String,
    docs: usize,
    queries: usize,
    selectivity: f64,
    p50_ns: u128,
    p95_ns: u128,
    p99_ns: u128,
    p999_ns: u128,
    max_ns: u128,
    budget_ns: u128,
    correct: bool,
    pass: bool,
}

fn run_cell(
    ty: &SearchType,
    tier: &str,
    n: usize,
    corpus: &Corpus,
    queries: usize,
) -> Result<Cell> {
    // Correctness on a small sample first (cheap O(N) brute-force each).
    let mut selectivity = 0.0;
    let correct = if ty.name == "duplicates" {
        let resp = corpus
            .engine
            .duplicates(
                COLL,
                DuplicatesRequest {
                    field: "tier".into(),
                    min_group_size: 2,
                    limit: 100,
                    offset: 0,
                },
            )
            .context("duplicates")?;
        resp.groups.iter().all(|g| g.external_ids.len() >= 2)
    } else {
        // knn is approximate → grade on MEAN recall over a larger sample;
        // exact types must score 1.0 on every sampled query.
        let sample = if ty.name == "knn" {
            queries.min(20).max(1)
        } else {
            queries.min(5).max(1)
        };
        let mut score_sum = 0.0;
        for q in 0..sample {
            let (score, sel) = verify(ty.name, q, corpus)?;
            score_sum += score;
            selectivity = sel;
        }
        let mean = score_sum / sample as f64;
        if ty.name == "knn" {
            mean >= 0.95
        } else {
            mean >= 0.999
        }
    };

    // Latency: each pass times `iters` calls; we keep the LEAST-CONTENDED pass
    // (lowest p99) — a min-of-N estimate that rejects transient OS/CPU spikes
    // (PERF-GOAL §0). The O(N) `group` op is expensive, so it runs fewer iters
    // and a single pass.
    let is_group = ty.class == Class::FullGroup;
    let iters = if is_group { queries.min(30) } else { queries };
    let passes = if is_group { 1 } else { 3 };
    let one_pass = || -> Result<Vec<u128>> {
        let mut samples = Vec::with_capacity(iters);
        if ty.name == "duplicates" {
            for _ in 0..iters {
                let t0 = Instant::now();
                let _ = corpus.engine.duplicates(
                    COLL,
                    DuplicatesRequest {
                        field: "tier".into(),
                        min_group_size: 2,
                        limit: 100,
                        offset: 0,
                    },
                )?;
                samples.push(t0.elapsed().as_nanos());
            }
        } else {
            let requests: Vec<SearchRequest> =
                (0..iters).map(|q| make_query(ty.name, q, corpus)).collect();
            for req in requests {
                let t0 = Instant::now();
                let _ = corpus.engine.search(COLL, req)?;
                samples.push(t0.elapsed().as_nanos());
            }
        }
        samples.sort_unstable();
        Ok(samples)
    };
    let mut samples = one_pass()?;
    for _ in 1..passes {
        let s = one_pass()?;
        if pct(&s, 0.99) < pct(&samples, 0.99) {
            samples = s;
        }
    }

    let budget = budget_ns(ty.class, n);
    let p99 = pct(&samples, 0.99);
    // The 50ms interactive SLO ceiling applies to search queries, not the batch
    // full-corpus `duplicates` (group) op — that has its own (larger) budget.
    let within_slo = is_group || p99 <= SLO_CEILING_NS;
    let pass = correct && p99 <= budget && within_slo;

    Ok(Cell {
        search: ty.name.into(),
        tier: tier.into(),
        docs: n,
        queries,
        selectivity,
        p50_ns: pct(&samples, 0.50),
        p95_ns: pct(&samples, 0.95),
        p99_ns: p99,
        p999_ns: pct(&samples, 0.999),
        max_ns: *samples.last().unwrap_or(&0),
        budget_ns: budget,
        correct,
        pass,
    })
}

// ---------------------------------------------------------------------------
// CLI
// ---------------------------------------------------------------------------

#[derive(Parser)]
#[command(name = "lumen-bench", about = "lumen performance + correctness matrix")]
struct Cli {
    #[command(subcommand)]
    cmd: Cmd,
}

#[derive(Subcommand)]
enum Cmd {
    /// Build corpora and measure the (type × tier) matrix.
    Run {
        /// Comma-separated tiers: xs(1k) s(10k) m(100k) l(1M) xl(10M).
        #[arg(long, default_value = "xs,s,m")]
        tiers: String,
        /// Comma-separated search types (default: all).
        #[arg(long)]
        types: Option<String>,
        /// Queries per cell for the latency sample.
        #[arg(long, default_value_t = 2000)]
        queries: usize,
        /// Keyword cardinality (controls term/terms selectivity ≈ 1/cardinality).
        #[arg(long, default_value_t = 100)]
        cardinality: usize,
        /// Write the machine-readable report here.
        #[arg(long)]
        out: Option<String>,
        /// Optional baseline JSON to compare against (regression gate).
        #[arg(long)]
        baseline: Option<String>,
        /// Enforce the C3 scaling gate (exit non-zero on a violation).
        #[arg(long, default_value_t = false)]
        gate: bool,
    },
    /// Compare two reports against the ±10% regression threshold.
    Compare {
        #[arg(long)]
        baseline: String,
        #[arg(long)]
        against: String,
    },
}

fn tier_docs(name: &str) -> Result<usize> {
    Ok(match name {
        "xs" => 1_000,
        "s" => 10_000,
        "m" => 100_000,
        "l" => 1_000_000,
        "xl" => 10_000_000,
        other => bail!("unknown tier '{other}' (xs|s|m|l|xl)"),
    })
}

fn main() -> Result<()> {
    match Cli::parse().cmd {
        Cmd::Run {
            tiers,
            types,
            queries,
            cardinality,
            out,
            baseline,
            gate,
        } => run(tiers, types, queries, cardinality, out, baseline, gate),
        Cmd::Compare { baseline, against } => compare(&baseline, &against),
    }
}

/// C3 scaling gate. For the classes that should be sub-linear in corpus size
/// (`knn` via HNSW is the genuine O(log N) case), the ratio of the largest-tier
/// p99 to the smallest-tier p99 must be ≤ 4× (linear growth ⇒ FAIL). For
/// `term`/`terms`/`range` the ratio is *reported* but not gated: those paths
/// materialize the whole posting set (constant_score), so at fixed selectivity
/// the matched set — and thus p99 — grows with N (O(matched-set), not O(log N));
/// making them O(log N) needs top-k over pre-sorted postings (recorded blocker).
fn check_scaling(cells: &[Cell]) -> Vec<String> {
    use std::collections::BTreeMap;
    // Tested at a FIXED matched-set (TARGET_MATCHES) across tiers, so these
    // classes should be SUB-LINEAR in corpus size: term/terms/range become
    // ~flat (index lookup, not full scan) and knn is HNSW (~log). The gate is
    // `ratio ≤ √span` (floored at ×4 for small spans): a full scan would be
    // ~×span and fail; sub-linear growth passes.
    let gated: &[&str] = &["term", "terms", "range", "knn"];
    let mut by_search: BTreeMap<&str, Vec<&Cell>> = BTreeMap::new();
    for c in cells {
        by_search.entry(c.search.as_str()).or_default().push(c);
    }
    let mut violations = Vec::new();
    for (search, mut cs) in by_search {
        if !gated.contains(&search) {
            continue;
        }
        cs.sort_by_key(|c| c.docs);
        if cs.len() < 2 {
            continue;
        }
        let (lo, hi) = (cs.first().unwrap(), cs.last().unwrap());
        if lo.p99_ns == 0 {
            continue;
        }
        let ratio = hi.p99_ns as f64 / lo.p99_ns as f64;
        let span = hi.docs as f64 / lo.docs as f64;
        let allowed = span.sqrt().max(4.0);
        println!(
            "scaling {:<6} docs ×{:.0}  p99 ×{:.2}  (allowed ≤×{:.1};  {} → {})",
            search,
            span,
            ratio,
            allowed,
            fmt_ns(lo.p99_ns),
            fmt_ns(hi.p99_ns)
        );
        if ratio > allowed {
            violations.push(format!(
                "{search}: p99 grew ×{ratio:.1} over ×{span:.0} docs (sub-linear bound ≤×{allowed:.1})"
            ));
        }
    }
    violations
}

fn run(
    tiers: String,
    types: Option<String>,
    queries: usize,
    cardinality: usize,
    out: Option<String>,
    baseline: Option<String>,
    gate: bool,
) -> Result<()> {
    let tier_names: Vec<String> = tiers.split(',').map(|s| s.trim().to_string()).collect();
    let want_types: Option<HashSet<String>> =
        types.map(|t| t.split(',').map(|s| s.trim().to_string()).collect());
    let selected: Vec<&SearchType> = TYPES
        .iter()
        .filter(|t| {
            want_types
                .as_ref()
                .map(|w| w.contains(t.name))
                .unwrap_or(true)
        })
        .collect();

    let mut cells = Vec::new();
    for tname in &tier_names {
        let n = tier_docs(tname)?;
        let need_vec = selected.iter().any(|t| t.needs_vec);
        // HNSW build is heavy; run vectors through L (1M) but not XL (10M).
        let with_vec = need_vec && n <= 1_000_000;
        if need_vec && !with_vec {
            eprintln!(">> skipping knn at tier {tname} (vector build capped at L=1M)");
        }
        // Cardinality derives from N so each query's matched set stays
        // ~TARGET_MATCHES across tiers (the scaling test holds result size
        // fixed). The --cardinality CLI value is overridden for this reason.
        let _ = cardinality;
        let card = cardinality_for(n);
        eprintln!(">> building corpus tier={tname} docs={n} cardinality={card} vec={with_vec}");
        let corpus = build_corpus(n, card, with_vec)?;

        for ty in &selected {
            if ty.needs_vec && !corpus.with_vec {
                continue;
            }
            let cell = run_cell(ty, tname, n, &corpus, queries)?;
            eprintln!(
                "   {:<13} {:<3} p50={:>8} p99={:>8} budget={:>8} sel={:.4} {} {}",
                cell.search,
                cell.tier,
                fmt_ns(cell.p50_ns),
                fmt_ns(cell.p99_ns),
                fmt_ns(cell.budget_ns),
                cell.selectivity,
                if cell.correct { "ok" } else { "WRONG" },
                if cell.pass { "PASS" } else { "FAIL" },
            );
            cells.push(cell);
        }
    }

    print_table(&cells);
    let passed = cells.iter().filter(|c| c.pass).count();
    println!("\n{passed}/{} cells PASS", cells.len());

    // C3 scaling gate (needs ≥2 tiers to compute a ratio).
    let scaling_violations = check_scaling(&cells);
    for v in &scaling_violations {
        println!("!! scaling: {v}");
    }

    if let Some(path) = out {
        std::fs::write(&path, serde_json::to_string_pretty(&cells)?)
            .with_context(|| format!("write {path}"))?;
        eprintln!(">> wrote {path}");
    }
    if let Some(base) = baseline {
        let prev: Vec<Cell> = serde_json::from_str(&std::fs::read_to_string(&base)?)?;
        report_regressions(&prev, &cells);
    }

    let cell_fail = cells.iter().any(|c| !c.pass);
    let scaling_fail = gate && !scaling_violations.is_empty();
    if cell_fail || scaling_fail {
        std::process::exit(1);
    }
    Ok(())
}

fn fmt_ns(ns: u128) -> String {
    if ns >= 1_000_000 {
        format!("{:.2}ms", ns as f64 / 1e6)
    } else if ns >= 1_000 {
        format!("{:.1}µs", ns as f64 / 1e3)
    } else {
        format!("{ns}ns")
    }
}

fn print_table(cells: &[Cell]) {
    println!(
        "\n{:<13} {:<4} {:>10} {:>10} {:>10} {:>10} {:>10} {:>8} {:>6} {:>5}",
        "search", "tier", "p50", "p95", "p99", "p999", "budget", "sel%", "ok", "pass"
    );
    for c in cells {
        println!(
            "{:<13} {:<4} {:>10} {:>10} {:>10} {:>10} {:>10} {:>7.3} {:>6} {:>5}",
            c.search,
            c.tier,
            fmt_ns(c.p50_ns),
            fmt_ns(c.p95_ns),
            fmt_ns(c.p99_ns),
            fmt_ns(c.p999_ns),
            fmt_ns(c.budget_ns),
            c.selectivity * 100.0,
            if c.correct { "ok" } else { "WRONG" },
            if c.pass { "PASS" } else { "FAIL" },
        );
    }
}

fn compare(baseline: &str, against: &str) -> Result<()> {
    let prev: Vec<Cell> = serde_json::from_str(&std::fs::read_to_string(baseline)?)?;
    let cur: Vec<Cell> = serde_json::from_str(&std::fs::read_to_string(against)?)?;
    let regressed = report_regressions(&prev, &cur);
    if regressed {
        std::process::exit(1);
    }
    Ok(())
}

/// Report cells whose p99 grew > 10% vs the baseline. Returns true if any did.
fn report_regressions(prev: &[Cell], cur: &[Cell]) -> bool {
    let mut any = false;
    for c in cur {
        let Some(p) = prev
            .iter()
            .find(|x| x.search == c.search && x.tier == c.tier)
        else {
            continue;
        };
        if p.p99_ns == 0 {
            continue;
        }
        let change = (c.p99_ns as f64 - p.p99_ns as f64) / p.p99_ns as f64;
        let tag = if change > 0.10 {
            any = true;
            "REGRESSED"
        } else if change < -0.10 {
            "improved"
        } else {
            "~"
        };
        if tag != "~" {
            println!(
                "{:<13} {:<3} p99 {} -> {} ({:+.1}%) {}",
                c.search,
                c.tier,
                fmt_ns(p.p99_ns),
                fmt_ns(c.p99_ns),
                change * 100.0,
                tag
            );
        }
    }
    if any {
        println!("!! p99 regression > 10% — FAIL");
    }
    any
}
